def batch_import(config_list):
    """
    Run multiple imports from a configuration list.
    
    config_list: list of dicts with keys:
        - file_path (required)
        - table_name (required)
        - delimiter (optional, default ',')
        - enclosed_by (optional, default '"')
        - ignore_lines (optional, default 1)
        - replace (optional, default False)
    """
    results = []
    
    for i, config in enumerate(config_list):
        print(f"\n{'=' * 60}")
        print(f"Import {i + 1} of {len(config_list)}")
        print(f"{'=' * 60}")
        
        try:
            result = bulk_import(
                file_path=config['file_path'],
                table_name=config['table_name'],
                delimiter=config.get('delimiter', ','),
                enclosed_by=config.get('enclosed_by', '"'),
                ignore_lines=config.get('ignore_lines', 1),
                replace=config.get('replace', False),
            )
            result['status'] = 'success'
            result['file_path'] = config['file_path']
            result['table_name'] = config['table_name']
        except Exception as e:
            result = {
                'status': 'failed',
                'error': str(e),
                'file_path': config['file_path'],
                'table_name': config['table_name'],
            }
        
        results.append(result)
    
    # Print summary
    print(f"\n{'=' * 60}")
    print("BATCH IMPORT SUMMARY")
    print(f"{'=' * 60}")
    
    success_count = sum(1 for r in results if r['status'] == 'success')
    fail_count = sum(1 for r in results if r['status'] == 'failed')
    
    print(f"Total: {len(results)} | Success: {success_count} | Failed: {fail_count}")
    
    for r in results:
        status_icon = "✓" if r['status'] == 'success' else "✗"
        print(f"  {status_icon} {r['file_path']} -> {r['table_name']}: {r['status']}")
        if r['status'] == 'failed':
            print(f"    Error: {r['error']}")
    
    return results


